pistol_squat:{id:'pistol_squat',name:'Pistol Squat',nameAlt:['Squat une jambe','One Leg Squat'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Fessiers'],tertiaryMuscles:['Abdos (frontal)'],defaultRest:120,bwFactor:1.00,difficulty:4,tips:'Commence avec une chaise derrière toi. La mobilité de cheville est souvent le facteur limitant.',instructions:'1. Debout sur une jambe, l\'autre tendue devant\n2. Descendre en squat complet\n3. Remonter sans aide\n4. Garder le talon au sol',muscles:{primary:["quadriceps"],secondary:["glutes_major"],tertiary:["abs"]}},
squat_bodyweight:{id:'squat_bodyweight',name:'Squat Poids de Corps',nameAlt:['Bodyweight Squat','Air Squat'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Fessiers'],tertiaryMuscles:['Abdos (frontal)'],defaultRest:60,bwFactor:1.00,bwRatio:0.60,difficulty:1,instructions:'1. Debout, pieds largeur d\'épaules\n2. Descendre cuisses parallèles\n3. Dos droit, regard devant\n4. Remonter en poussant sur les talons',muscles:{primary:["quadriceps"],secondary:["glutes_major"],tertiary:["abs"]}},
cossack_squat:{id:'cossack_squat',name:'Squat Cossack',nameAlt:['Cossack Squat'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Adducteurs','Fessiers'],tertiaryMuscles:[],defaultRest:90,bwFactor:1.00,difficulty:3,instructions:'1. Debout, pieds très écartés\n2. Descendre sur une jambe latéralement\n3. L\'autre jambe reste tendue\n4. Alterner les côtés',muscles:{primary:["quadriceps"],secondary:["adductors","glutes_major"],tertiary:[]}},
nordic_curl:{id:'nordic_curl',name:'Nordic Curl',nameAlt:['Nordic Hamstring Curl'],equipment:'bodyweight',category:'isolation',trackingType:'reps',primaryMuscles:['Ischio-jambiers'],secondaryMuscles:[],tertiaryMuscles:[],defaultRest:120,bwFactor:1.00,difficulty:4,tips:'Commence par la descente seule (négatif). Utilise les mains pour remonter au début.',instructions:'1. À genoux, pieds bloqués\n2. Se pencher en avant LENTEMENT corps droit\n3. Résister le plus longtemps\n4. Se rattraper avec les mains',muscles:{primary:["hamstrings"],secondary:[],tertiary:[]}},
burpees:{id:'burpees',name:'Burpees',nameAlt:['Burpee'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Pecs','Épaules','Abdos (frontal)'],tertiaryMuscles:[],defaultRest:60,bwFactor:1.00,bwRatio:0.80,difficulty:2,instructions:'1. Debout, descendre mains au sol\n2. Lancer les pieds en arrière\n3. Faire une pompe\n4. Ramener les pieds, sauter',muscles:{primary:["quadriceps"],secondary:["chest_upper","shoulders_front","abs"],tertiary:[]}},
squat_jump:{id:'squat_jump',name:'Squat Jump',nameAlt:['Jump Squat','Squat sauté'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Fessiers','Mollets'],tertiaryMuscles:[],defaultRest:90,bwFactor:1.00,difficulty:2,instructions:'1. Position squat\n2. Descendre\n3. Sauter de manière explosive\n4. Atterrir en douceur',muscles:{primary:["quadriceps"],secondary:["glutes_major","calves_gastro"],tertiary:[]}},
lunge_jump:{id:'lunge_jump',name:'Fentes Sautées',nameAlt:['Jump Lunges'],equipment:'bodyweight',category:'compound',trackingType:'reps',primaryMuscles:['Quadriceps'],secondaryMuscles:['Fessiers'],tertiaryMuscles:['Mollets'],defaultRest:90,bwFactor:1.00,difficulty:3,instructions:'1. Position fente\n2. Sauter en l\'air\n3. Changer de jambe en l\'air\n4. Enchaîner en rythme',muscles:{primary:["quadriceps"],secondary:["glutes_major"],tertiary:["calves_gastro"]}},
