ring_dips:{id:'ring_dips',name:'Dips Anneaux',nameAlt:['Ring Dips'],equipment:'other',category:'compound',trackingType:'reps',primaryMuscles:['Pecs','Triceps'],secondaryMuscles:['Épaules (antérieur)'],tertiaryMuscles:['Abdos (frontal)'],defaultRest:150,bwFactor:0.95,difficulty:4,instructions:'1. En appui bras tendus sur les anneaux\n2. Tourner les anneaux vers l\'extérieur (RTO)\n3. Descendre en contrôlant\n4. Remonter bras tendus',muscles:{primary:["chest_lower","triceps"],secondary:["shoulders_front"],tertiary:["abs"]}},
