ring_support_hold:{id:'ring_support_hold',name:'Ring Support Hold',nameAlt:['Support Anneaux'],equipment:'other',category:'compound',trackingType:'time',primaryMuscles:['Épaules'],secondaryMuscles:['Abdos (frontal)','Triceps'],tertiaryMuscles:[],defaultRest:120,bwFactor:0.95,difficulty:3,instructions:'1. Se hisser en appui sur les anneaux\n2. Bras tendus, épaules basses\n3. Tourner les mains vers l\'extérieur\n4. Maintenir stable',muscles:{primary:["shoulders_front"],secondary:["abs","triceps"],tertiary:[]}},
