ring_face_pull:{id:'ring_face_pull',name:'Face Pull Anneaux',nameAlt:['Ring Face Pull'],equipment:'other',category:'isolation',trackingType:'reps',primaryMuscles:['Épaules (postérieur)'],secondaryMuscles:['Haut du dos'],tertiaryMuscles:[],defaultRest:60,bwFactor:0.50,difficulty:2,instructions:'1. Anneaux à hauteur de visage\n2. Se pencher en arrière, bras tendus\n3. Tirer vers le visage, coudes hauts\n4. Contrôler le retour',muscles:{primary:["shoulders_rear"],secondary:["rhomboids"],tertiary:[]}},
