floor_press_barbell:{id:'floor_press_barbell',name:'Floor Press (Barre)',nameAlt:['Développé couché au sol'],equipment:'barbell',category:'compound',trackingType:'weight',primaryMuscles:['Pecs'],secondaryMuscles:['Triceps'],tertiaryMuscles:[],defaultRest:120,difficulty:3,instructions:'1. Allongé au sol, barre au rack\n2. Descendre jusqu\'à ce que les coudes touchent le sol\n3. Pause 1 seconde\n4. Pousser pour remonter',muscles:{primary:["chest_upper"],secondary:["triceps"],tertiary:[]}},
