pendlay_row:{id:'pendlay_row',name:'Pendlay Row',nameAlt:['Rowing Pendlay','Strict Barbell Row'],equipment:'barbell',category:'compound',trackingType:'weight',primaryMuscles:['Haut du dos'],secondaryMuscles:['Grand dorsal','Biceps'],tertiaryMuscles:[],defaultRest:120,difficulty:3,instructions:'1. Barre au sol, position deadlift\n2. Dos parallèle au sol\n3. Tirer la barre vers les pecs\n4. Reposer la barre au SOL à chaque rep',muscles:{primary:["rhomboids"],secondary:["lats","biceps"],tertiary:[]}},
seal_row:{id:'seal_row',name:'Seal Row',nameAlt:['Rowing allongé','Chest Supported Row'],equipment:'barbell',category:'compound',trackingType:'weight',primaryMuscles:['Haut du dos'],secondaryMuscles:['Grand dorsal','Biceps'],tertiaryMuscles:[],defaultRest:90,difficulty:2,instructions:'1. Allongé face contre terre sur un banc surélevé\n2. Barre ou haltères sous le banc\n3. Tirer en serrant les omoplates\n4. Redescendre lentement',muscles:{primary:["rhomboids"],secondary:["lats","biceps"],tertiary:[]}},
trap_bar_deadlift:{id:'trap_bar_deadlift',name:'Trap Bar Deadlift',nameAlt:['Hex Bar Deadlift','SDT barre hexagonale'],equipment:'barbell',category:'compound',trackingType:'weight',primaryMuscles:['Quadriceps','Fessiers'],secondaryMuscles:['Ischio-jambiers','Lombaires','Trapèzes'],tertiaryMuscles:[],defaultRest:180,difficulty:2,tips:'Plus facile techniquement que le deadlift conventionnel. Excellente alternative pour les douleurs lombaires.',instructions:'1. À l\'intérieur de la barre hexagonale\n2. Dos droit, pousser le sol avec les pieds\n3. Se lever dos neutre\n4. Reposer en contrôlant',muscles:{primary:["quadriceps"],secondary:["glutes_major","hamstrings"],tertiary:[]}},
good_morning:{id:'good_morning',name:'Good Morning',nameAlt:['Bonjour Barre'],equipment:'barbell',category:'compound',trackingType:'weight',primaryMuscles:['Ischio-jambiers'],secondaryMuscles:['Lombaires','Fessiers'],tertiaryMuscles:[],defaultRest:120,difficulty:3,instructions:'1. Barre sur les trapèzes\n2. Genoux légèrement fléchis\n3. Pencher le buste en poussant les fesses en arrière\n4. Remonter en contractant les fessiers',muscles:{primary:["hamstrings"],secondary:["abs","glutes_major","erectors"],tertiary:[]}},
hyperextension:{id:'hyperextension',name:'Hyperextension',nameAlt:['Back Extension','Extension lombaire'],equipment:'bodyweight',category:'isolation',trackingType:'reps',primaryMuscles:['Lombaires'],secondaryMuscles:['Fessiers'],tertiaryMuscles:[],defaultRest:60,difficulty:1,instructions:'1. Banc à 45° ou GHD, hanches sur le support\n2. Descendre le buste vers le sol\n3. Remonter jusqu\'à l\'alignement\n4. Contrôler le mouvement',muscles:{primary:["erectors"],secondary:["glutes_major"],tertiary:[]}},
