sled_push:{id:'sled_push',name:'Sled Push',nameAlt:['Poussée traîneau'],equipment:'other',category:'compound',trackingType:'time',primaryMuscles:['Quadriceps'],secondaryMuscles:['Fessiers','Mollets'],tertiaryMuscles:[],defaultRest:120,difficulty:2,instructions:'1. Mains sur les poignées du traîneau\n2. Corps penché en avant\n3. Pousser pas courts et rapides\n4. Dos droit',muscles:{primary:["quadriceps"],secondary:["calves_gastro","chest_upper","glutes_major"],tertiary:[]}},
