external_rotation_cable:{id:'external_rotation_cable',name:'Rotation Externe (Câble)',nameAlt:['Cable External Rotation'],equipment:'cable',category:'isolation',trackingType:'weight',primaryMuscles:['Épaules (postérieur)'],secondaryMuscles:[],tertiaryMuscles:[],defaultRest:45,difficulty:1,instructions:'1. Câble à hauteur de coude\n2. Coude collé au flanc\n3. Tourner l\'avant-bras vers l\'extérieur\n4. Mouvement lent et contrôlé',muscles:{primary:["shoulders_rear"],secondary:[],tertiary:[]}},
