sprint:{id:'sprint',name:'Sprint',nameAlt:['Course sprint'],equipment:'bodyweight',category:'cardio',trackingType:'cardio',primaryMuscles:['Quadriceps'],secondaryMuscles:['Ischio-jambiers','Mollets','Fessiers'],tertiaryMuscles:[],defaultRest:120,difficulty:2,instructions:'1. Sprint maximal sur 50-100m\n2. Décélérer progressivement\n3. Récupérer en marchant',muscles:{primary:["quadriceps"],secondary:["hamstrings","calves_gastro","glutes_major"],tertiary:[]}},
